@implements IAsyncDisposable

<CascadingValue Value="@currentSize" Name="ScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;

    private IJSObjectReference? module;
    private DotNetObjectReference<ScreenSizeProvider>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/ScreenSizeProvider.razor.js");
            await module.InvokeVoidAsync("initialize", dotNetRef);
        }
    }

    [JSInvokable]
    public void OnViewportCategoryChanged(string category)
    {
        var newSize = category switch
        {
            "Mobile" => ScreenSize.Mobile,
            "Tablet" => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize != currentSize)
        {
            currentSize = newSize;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

namespace sv_cb23d39416b94c338f69e584361b583b.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

let dotNetRef = null;
let lastCategory = null;

function getCategory() {
    const width = window.innerWidth;
    if (width < 768) return "Mobile";
    if (width < 1024) return "Tablet";
    return "Desktop";
}

function onResize() {
    const category = getCategory();
    if (category !== lastCategory) {
        lastCategory = category;
        dotNetRef?.invokeMethodAsync("OnViewportCategoryChanged", category);
    }
}

export function initialize(ref) {
    dotNetRef = ref;
    lastCategory = getCategory();
    dotNetRef.invokeMethodAsync("OnViewportCategoryChanged", lastCategory);
    window.addEventListener("resize", onResize);
}

export function dispose() {
    window.removeEventListener("resize", onResize);
    dotNetRef = null;
    lastCategory = null;
}

